//! # Hello Data Holograph — Data-as-Shape Handshake
//!
//! Encodes a literal string into a Topological QR (Spatial Fingerprint),
//! saves it as a PNG, and re-materializes the data from the image grid.

use distributed_inference::topological_qr::TopologicalQR;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let message = "HELLO:MONSTER";
    println!(" [ GENERATING DATA HANDSHAKE ] ");
    println!(" Message: \"{}\"", message);

    // 1. Encode Data into Topological QR (Spatial Fingerprint)
    let qr = TopologicalQR::encode_data(message.as_bytes());

    // 2. Save PNG Artifact
    let png_path = "hello_data_fingerprint.png";
    qr.save_as_png(png_path)?;
    println!(" Saved to: {}", png_path);

    // 3. Re-materialize (Decode from the internal grid)
    let decoded_bytes = qr.decode_data();
    let decoded_message = String::from_utf8_lossy(&decoded_bytes);

    println!(" [ RE-MATERIALIZATION ] ");
    println!(" Decoded: \"{}\"", decoded_message);

    if message == decoded_message {
        println!(" [ SUCCESS ] Message re-materialized from spatial shape.");
    } else {
        println!(" [ FAILURE ] Data mismatch.");
    }

    Ok(())
}
